// tlExpressionMixerChunk

int tlExpressionMixerChunk::sortPriority = -1;

tlExpressionMixerChunk::tlExpressionMixerChunk()
{
    Init();
}

tlExpressionMixerChunk::tlExpressionMixerChunk(const tlExpressionMixerChunk& ch)
{
    Init();
    *this = ch;
}

tlExpressionMixerChunk::~tlExpressionMixerChunk()
{

    if(name != NULL){
        strdelete(name);
    }
    if(targetname != NULL){
        strdelete(targetname);
    }
    if(expressiongroupname != NULL){
        strdelete(expressiongroupname);
    }
}

tlExpressionMixerChunk::tlExpressionMixerChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Expression::VERTEX_EXPRESSION_MIXER);
    ident = Pure3D::Expression::VERTEX_EXPRESSION_MIXER;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    version = f->GetLong();
    f->GetPString(buf);
    name = strnew(buf);
    type = f->GetLong();
    f->GetPString(buf);
    targetname = strnew(buf);
    f->GetPString(buf);
    expressiongroupname = strnew(buf);
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Expression::VERTEX_EXPRESSION_MIXER);
    }
}

void
tlExpressionMixerChunk::Init()
{
    ident = Pure3D::Expression::VERTEX_EXPRESSION_MIXER;
    version = 0;
    name = NULL;
    type = 0;
    targetname = NULL;
    expressiongroupname = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Expression::VERTEX_EXPRESSION_MIXER);
    }
}

long 
tlExpressionMixerChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += strlen( name );
    s += sizeof( type );
    s += strlen( targetname );
    s += strlen( expressiongroupname );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlExpressionMixerChunk&
tlExpressionMixerChunk::operator=(const tlExpressionMixerChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    name = strnew(a.name);
    type = a.type;
    targetname = strnew(a.targetname);
    expressiongroupname = strnew(a.expressiongroupname);

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlExpressionMixerChunk::operator==(const tlDataChunk& a)
{

    const tlExpressionMixerChunk* aptr = dynamic_cast<const tlExpressionMixerChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(type == aptr->type))
    {
        return false;
    }
    if(strcmp(targetname, aptr->targetname) != 0)
    {
        return false;
    }
    if(strcmp(expressiongroupname, aptr->expressiongroupname) != 0)
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlExpressionMixerChunk::NameCompare(const tlDataChunk& a)
{

    const tlExpressionMixerChunk* aptr = dynamic_cast<const tlExpressionMixerChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


tlDataChunk*
tlExpressionMixerChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlExpressionMixerChunk(ch);
    return dtCh;
}

void
tlExpressionMixerChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutLong(version);
        f->PutPString(name);
        f->PutLong(type);
        f->PutPString(targetname);
        f->PutPString(expressiongroupname);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlExpressionMixerChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlExpressionMixerChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Version             = %ld\n",indent,"",version);
    printf("%*s  Name                = \"%s\"\n",indent,"",name);
    printf("%*s  Type                = %ld\n",indent,"",type);
    printf("%*s  TargetName          = \"%s\"\n",indent,"",targetname);
    printf("%*s  ExpressionGroupName = \"%s\"\n",indent,"",expressiongroupname);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlExpressionMixerChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # Version            \n",indent,"",version);
    printf("%*s  pstring \"%s\" # Name               \n",indent,"",name);
    printf("%*s  int   %12ld # Type               \n",indent,"",type);
    printf("%*s  pstring \"%s\" # TargetName         \n",indent,"",targetname);
    printf("%*s  pstring \"%s\" # ExpressionGroupName\n",indent,"",expressiongroupname);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

